/**
 * AWS Lambda: nightly daily game generation for TubeRush.
 * Triggered by EventBridge Scheduler (cron). Ported from Supabase Edge Function.
 * Secrets fetched from AWS Secrets Manager and cached for warm invocations.
 */

import { SecretsManagerClient, GetSecretValueCommand } from '@aws-sdk/client-secrets-manager';
import type { ScheduledEvent, Context } from 'aws-lambda';

// ---------------------------------------------------------------------------
// Constants — tuned for 5-minute Lambda cap
// ---------------------------------------------------------------------------

const ANTHROPIC_API_URL = 'https://api.anthropic.com/v1/messages';
const CLAUDE_MODEL = 'claude-sonnet-4-6';
const CLAUDE_TIMEOUT_MS = 25_000;       // 25s per simple call
const CLAUDE_SKILL_TIMEOUT_MS = 60_000; // 60s per skill call (pause-turn loop)
const MAX_RETRIES = 1;                  // 2 total attempts per puzzle
const MAX_PAUSE_TURNS = 8;
const ANTHROPIC_BETA_SKILLS = 'code-execution-2025-08-25,skills-2025-10-02';
const GROUP_COLORS = ['#DC241F', '#007D32', '#0019A8', '#FFD329'];

// ---------------------------------------------------------------------------
// Secrets (cached across warm invocations)
// ---------------------------------------------------------------------------

interface Secrets {
  ANTHROPIC_API_KEY: string;
  SUPABASE_URL: string;
  SUPABASE_SERVICE_ROLE_KEY: string;
  ANTHROPIC_DAILY_PUZZLE_SKILL_ID?: string;
  ANTHROPIC_DAILY_PUZZLE_SKILL_VERSION?: string;
  DISABLE_CLAUDE_SKILL?: string;
}

const secretsClient = new SecretsManagerClient({});
let cachedSecrets: Secrets | null = null;

async function getSecrets(): Promise<Secrets> {
  if (cachedSecrets) return cachedSecrets;
  const secretArn = process.env.SECRET_ARN;
  if (!secretArn) throw new Error('SECRET_ARN env var not set');
  const res = await secretsClient.send(new GetSecretValueCommand({ SecretId: secretArn }));
  if (!res.SecretString) throw new Error('Secret has no string value');
  cachedSecrets = JSON.parse(res.SecretString) as Secrets;
  return cachedSecrets;
}

// ---------------------------------------------------------------------------
// Logging
// ---------------------------------------------------------------------------

function log(step: string, detail?: unknown) {
  try {
    console.log(JSON.stringify({ step, detail, ts: new Date().toISOString() }));
  } catch {
    console.log(`[${step}]`);
  }
}

// ---------------------------------------------------------------------------
// PostgREST helpers (raw fetch — mirrors the edge function approach)
// ---------------------------------------------------------------------------

function baseUrl(raw: string): string {
  return raw.replace(/\/$/, '');
}

function restHeaders(
  serviceKey: string,
  extra?: Record<string, string>,
): Record<string, string> {
  return {
    apikey: serviceKey,
    Authorization: `Bearer ${serviceKey}`,
    Accept: 'application/json',
    'Content-Type': 'application/json',
    ...extra,
  };
}

async function restGameExists(
  supabaseUrl: string,
  serviceKey: string,
  gameType: string,
  gameDate: string,
): Promise<boolean> {
  const q = new URLSearchParams({
    select: 'id',
    game_type: `eq.${gameType}`,
    game_date: `eq.${gameDate}`,
    limit: '1',
  });
  const url = `${baseUrl(supabaseUrl)}/rest/v1/games?${q.toString()}`;
  const res = await fetch(url, { headers: restHeaders(serviceKey) });
  if (!res.ok) {
    const t = await res.text().catch(() => '');
    log('rest_select_warn', { status: res.status, body: t.slice(0, 200) });
    return false;
  }
  const rows: unknown = await res.json().catch(() => []);
  return Array.isArray(rows) && rows.length > 0;
}

async function restNextval(
  supabaseUrl: string,
  serviceKey: string,
  seqName: string,
  fallback: number,
): Promise<string> {
  const url = `${baseUrl(supabaseUrl)}/rest/v1/rpc/nextval_text`;
  const res = await fetch(url, {
    method: 'POST',
    headers: restHeaders(serviceKey),
    body: JSON.stringify({ seq_name: seqName }),
  });
  if (!res.ok) {
    const t = await res.text().catch(() => '');
    log('rest_rpc_warn', { seqName, status: res.status, body: t.slice(0, 200) });
    return String(fallback);
  }
  const val: unknown = await res.json().catch(() => null);
  if (val != null && val !== '') return String(val);
  return String(fallback);
}

type InsertResult = 'inserted' | 'duplicate';

async function restInsertGame(
  supabaseUrl: string,
  serviceKey: string,
  row: {
    game_type: string;
    game_date: string;
    puzzle_data: unknown;
    is_published: boolean;
  },
): Promise<InsertResult> {
  const url = `${baseUrl(supabaseUrl)}/rest/v1/games`;
  const res = await fetch(url, {
    method: 'POST',
    headers: restHeaders(serviceKey, { Prefer: 'return=minimal' }),
    body: JSON.stringify(row),
  });
  if (res.status === 201 || res.status === 200) return 'inserted';
  if (res.status === 409) return 'duplicate';
  const t = await res.text().catch(() => '');
  throw new Error(`REST insert games ${res.status}: ${t.slice(0, 500)}`);
}

// ---------------------------------------------------------------------------
// Claude
// ---------------------------------------------------------------------------

function getDailyPuzzleSkillConfig(
  secrets: Secrets,
): { skillId: string; version: string } | null {
  if (secrets.DISABLE_CLAUDE_SKILL === '1') return null;
  const skillId = secrets.ANTHROPIC_DAILY_PUZZLE_SKILL_ID?.trim();
  if (!skillId) return null;
  const version = secrets.ANTHROPIC_DAILY_PUZZLE_SKILL_VERSION?.trim() || 'latest';
  return { skillId, version };
}

function joinTextFromContentBlocks(content: unknown): string {
  if (!Array.isArray(content)) return '';
  const parts: string[] = [];
  for (const block of content) {
    if (block && typeof block === 'object' && 'type' in block) {
      const b = block as { type: string; text?: string };
      if (b.type === 'text' && typeof b.text === 'string') parts.push(b.text);
    }
  }
  return parts.join('\n');
}

async function callClaudeSimple(apiKey: string, system: string, prompt: string): Promise<string> {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), CLAUDE_TIMEOUT_MS);
  try {
    const res = await fetch(ANTHROPIC_API_URL, {
      method: 'POST',
      signal: controller.signal,
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
      },
      body: JSON.stringify({
        model: CLAUDE_MODEL,
        max_tokens: 4096,
        system,
        messages: [{ role: 'user', content: prompt }],
      }),
    });
    if (!res.ok) {
      const body = await res.text().catch(() => '(unreadable body)');
      throw new Error(`Claude ${res.status}: ${body.slice(0, 400)}`);
    }
    let data: unknown;
    try {
      data = await res.json();
    } catch {
      throw new Error('Claude response was not valid JSON');
    }
    if (data == null || typeof data !== 'object') {
      throw new Error('Claude JSON was empty or not an object');
    }
    const text = joinTextFromContentBlocks((data as { content?: unknown }).content);
    if (!text.trim()) {
      throw new Error(`Empty Claude text; keys=${Object.keys(data as object).join(',')}`);
    }
    return text;
  } finally {
    clearTimeout(timer);
  }
}

async function callClaudeWithSkill(
  apiKey: string,
  system: string,
  userPrompt: string,
  skill: { skillId: string; version: string },
): Promise<string> {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), CLAUDE_SKILL_TIMEOUT_MS);

  const tools = [{ type: 'code_execution_20250825', name: 'code_execution' }];
  const skillEntry = { type: 'custom' as const, skill_id: skill.skillId, version: skill.version };

  type Msg = { role: 'user' | 'assistant'; content: unknown };
  const messages: Msg[] = [{ role: 'user', content: userPrompt }];
  let container: Record<string, unknown> = { skills: [skillEntry] };

  try {
    for (let turn = 0; turn < MAX_PAUSE_TURNS; turn++) {
      const res = await fetch(ANTHROPIC_API_URL, {
        method: 'POST',
        signal: controller.signal,
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': apiKey,
          'anthropic-version': '2023-06-01',
          'anthropic-beta': ANTHROPIC_BETA_SKILLS,
        },
        body: JSON.stringify({
          model: CLAUDE_MODEL,
          max_tokens: 8192,
          system,
          messages,
          tools,
          container,
        }),
      });

      if (!res.ok) {
        const body = await res.text().catch(() => '(unreadable body)');
        throw new Error(`Claude (skills) ${res.status}: ${body.slice(0, 500)}`);
      }

      let data: unknown;
      try {
        data = await res.json();
      } catch {
        throw new Error('Claude (skills) response was not valid JSON');
      }
      if (data == null || typeof data !== 'object') {
        throw new Error('Claude (skills) JSON was empty or not an object');
      }

      const payload = data as {
        stop_reason?: string;
        content?: unknown;
        container?: { id?: string };
      };
      const stopReason = payload.stop_reason;
      const text = joinTextFromContentBlocks(payload.content);

      log('claude_skill_turn', {
        turn,
        stop_reason: stopReason,
        text_len: text.length,
        container_id: payload.container?.id,
      });

      if (stopReason !== 'pause_turn') {
        if (!text.trim()) {
          throw new Error(
            `Empty Claude (skills) stop_reason=${stopReason} snippet=${JSON.stringify(data).slice(0, 300)}`,
          );
        }
        return text;
      }

      const cid = payload.container?.id;
      if (!cid) throw new Error('pause_turn but missing container.id');

      messages.push({ role: 'assistant', content: payload.content });
      container = { id: cid, skills: [skillEntry] };
    }
    throw new Error(`Exceeded MAX_PAUSE_TURNS (${MAX_PAUSE_TURNS})`);
  } finally {
    clearTimeout(timer);
  }
}

async function callClaude(
  apiKey: string,
  secrets: Secrets,
  system: string,
  prompt: string,
): Promise<string> {
  const skill = getDailyPuzzleSkillConfig(secrets);
  if (skill) {
    log('claude_mode', { mode: 'skill', skill_id: skill.skillId });
    const systemWithSkill =
      `The "Daily Puzzle Generator" Agent Skill is active. Use it for quality, then output ONLY JSON (no markdown).\n\n${system}`;
    const userWithSkill = `Apply the skill, then output only this JSON task:\n\n${prompt}`;
    try {
      return await callClaudeWithSkill(apiKey, systemWithSkill, userWithSkill, skill);
    } catch (e) {
      const msg = e instanceof Error ? e.message : String(e);
      log('claude_skill_fallback', { reason: msg.slice(0, 200) });
      return callClaudeSimple(apiKey, system, prompt);
    }
  }
  log('claude_mode', { mode: 'messages_only' });
  return callClaudeSimple(apiKey, system, prompt);
}

function extractJSON(text: string): string {
  const fenced = text.match(/```(?:json)?\s*\n?([\s\S]*?)```/);
  if (fenced) return fenced[1].trim();
  const braces = text.match(/\{[\s\S]*\}/);
  if (braces) return braces[0].trim();
  return text.trim();
}

// ---------------------------------------------------------------------------
// Puzzles
// ---------------------------------------------------------------------------

const CONNECTIONS_SYSTEM = `You are a puzzle designer for TubeRush, a London-themed daily word game. Create "Connections" puzzles: four groups of four related words.

Rules:
- Exactly 4 groups, each with exactly 4 items. Difficulty 1 (easy) to 4 (hard).
- Items: single words or very short phrases (2-3 words max), ALL CAPS.
- At least one London/British culture group. Mix topics: pop culture, wordplay, geography, history, food, etc.
- Some items should plausibly fit multiple groups. No duplicates across groups.
- Return ONLY a JSON object, no markdown fences, no extra text.`;

function connectionsPrompt(date: string, id: string): string {
  return `Connections puzzle for ${date} (#${id}). Return: {"groups":[{"category":"NAME","items":["A","B","C","D"],"difficulty":1}, ...4 groups]}`;
}

function validateConnections(
  d: unknown,
): d is { groups: { category: string; items: string[]; difficulty: number }[] } {
  if (!d || typeof d !== 'object') return false;
  const o = d as Record<string, unknown>;
  if (!Array.isArray(o.groups) || o.groups.length !== 4) return false;
  const seen = new Set<string>();
  for (const g of o.groups as Record<string, unknown>[]) {
    if (typeof g.category !== 'string') return false;
    if (!Array.isArray(g.items) || g.items.length !== 4) return false;
    if (typeof g.difficulty !== 'number' || g.difficulty < 1 || g.difficulty > 4) return false;
    for (const item of g.items) {
      if (typeof item !== 'string' || !item) return false;
      if (seen.has(item)) return false;
      seen.add(item);
    }
  }
  return seen.size === 16;
}

async function generateConnections(
  apiKey: string,
  secrets: Secrets,
  date: string,
  id: string,
) {
  let lastErr: unknown;
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      log('claude_call', { type: 'connections', date, attempt });
      const raw = await callClaude(apiKey, secrets, CONNECTIONS_SYSTEM, connectionsPrompt(date, id));
      const parsed = JSON.parse(extractJSON(raw));
      if (!validateConnections(parsed)) {
        throw new Error(`Invalid structure: ${JSON.stringify(parsed).slice(0, 200)}`);
      }
      return {
        id,
        date,
        groups: parsed.groups.map((g, i) => ({ ...g, color: GROUP_COLORS[i] })),
      };
    } catch (err) {
      lastErr = err;
      log('claude_error', { type: 'connections', date, attempt, error: String(err).slice(0, 300) });
    }
  }
  throw lastErr instanceof Error ? lastErr : new Error(String(lastErr));
}

const CROSSWORD_SYSTEM = `You are a crossword puzzle designer for TubeRush, a London-themed daily word game. Create 5x5 mini crosswords.

Rules:
- Grid: exactly 5x5. Use 3-6 black squares. Words >= 3 letters, all interlocking correctly.
- At least some London/British themed clues. Clues should be clever and concise.
- Number cells that start across/down words, in reading order starting at 1.
- Return ONLY a JSON object, no markdown fences, no extra text.`;

function crosswordPrompt(date: string, id: string): string {
  return `5x5 crossword for ${date} (#${id}). Return: {"title":"Title","grid":[[{"letter":"A","number":1,"isBlack":false},...],...5 rows],"clues":{"across":[{"number":1,"clue":"...","answer":"WORD","row":0,"col":0,"length":4}],"down":[...]}}. Black squares: {"letter":null,"isBlack":true}. "number" only on cells starting a clue.`;
}

function validateCrossword(d: unknown): boolean {
  if (!d || typeof d !== 'object') return false;
  const o = d as Record<string, unknown>;
  if (typeof o.title !== 'string') return false;
  if (!Array.isArray(o.grid) || o.grid.length !== 5) return false;
  for (const row of o.grid as unknown[][]) {
    if (!Array.isArray(row) || row.length !== 5) return false;
    for (const cell of row as Record<string, unknown>[]) {
      if (typeof cell.isBlack !== 'boolean') return false;
      if (!cell.isBlack && (typeof cell.letter !== 'string' || (cell.letter as string).length !== 1)) return false;
    }
  }
  const c = o.clues as Record<string, unknown> | undefined;
  if (!c || !Array.isArray(c.across) || !Array.isArray(c.down)) return false;
  if (c.across.length === 0 && c.down.length === 0) return false;
  for (const cl of [
    ...(c.across as Record<string, unknown>[]),
    ...(c.down as Record<string, unknown>[]),
  ]) {
    if (typeof cl.number !== 'number' || typeof cl.clue !== 'string') return false;
    if (typeof cl.answer !== 'string' || (cl.answer as string).length < 3) return false;
    if (typeof cl.row !== 'number' || typeof cl.col !== 'number' || typeof cl.length !== 'number')
      return false;
  }
  return true;
}

function normalizeGrid(grid: Record<string, unknown>[][]) {
  return grid.map(row =>
    row.map(cell => {
      if (cell.isBlack) return { letter: null, isBlack: true };
      const out: Record<string, unknown> = {
        letter: (cell.letter as string).toUpperCase(),
        isBlack: false,
      };
      if (cell.number != null) out.number = cell.number;
      return out;
    }),
  );
}

async function generateCrossword(
  apiKey: string,
  secrets: Secrets,
  date: string,
  id: string,
) {
  let lastErr: unknown;
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      log('claude_call', { type: 'crossword', date, attempt });
      const raw = await callClaude(apiKey, secrets, CROSSWORD_SYSTEM, crosswordPrompt(date, id));
      const parsed = JSON.parse(extractJSON(raw));
      if (!validateCrossword(parsed)) {
        throw new Error(`Invalid structure: ${JSON.stringify(parsed).slice(0, 200)}`);
      }
      return {
        id,
        date,
        title: parsed.title,
        rows: 5,
        cols: 5,
        grid: normalizeGrid(parsed.grid),
        clues: { across: parsed.clues.across, down: parsed.clues.down },
      };
    } catch (err) {
      lastErr = err;
      log('claude_error', { type: 'crossword', date, attempt, error: String(err).slice(0, 300) });
    }
  }
  throw lastErr instanceof Error ? lastErr : new Error(String(lastErr));
}

// ---------------------------------------------------------------------------
// Dates
// ---------------------------------------------------------------------------

function formatDate(d: Date): string {
  return d.toISOString().split('T')[0];
}

async function findNextMissingDate(
  supabaseUrl: string,
  serviceKey: string,
  gameType: string,
  maxDaysAhead: number,
): Promise<string | null> {
  const today = new Date();
  for (let i = 0; i < maxDaysAhead; i++) {
    const d = new Date(today);
    d.setDate(d.getDate() + i);
    const dateStr = formatDate(d);
    if (!(await restGameExists(supabaseUrl, serviceKey, gameType, dateStr))) return dateStr;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Lambda handler
// ---------------------------------------------------------------------------

interface LambdaEvent extends Partial<ScheduledEvent> {
  days_ahead?: number; // override for manual invocations
  count?: number;      // number of game pairs to generate (max 3)
}

interface HandlerResult {
  success: boolean;
  generated: number;
  elapsed_ms: number;
  results: { date: string; game_type: string; status: string; detail?: string }[];
  had_errors: boolean;
  error?: string;
}

export async function handler(
  event: LambdaEvent,
  _context: Context,
): Promise<HandlerResult> {
  const startMs = Date.now();

  try {
    const secrets = await getSecrets();

    const daysAhead =
      typeof event.days_ahead === 'number' && event.days_ahead > 0 ? event.days_ahead : 8;
    const count =
      typeof event.count === 'number' && event.count > 0 ? Math.min(event.count, 3) : 1;

    const skillCfg = getDailyPuzzleSkillConfig(secrets);
    log('start', {
      daysAhead,
      count,
      skill: skillCfg ? { id: skillCfg.skillId, version: skillCfg.version } : null,
    });

    const { ANTHROPIC_API_KEY: anthropicApiKey, SUPABASE_URL: supabaseUrl, SUPABASE_SERVICE_ROLE_KEY: serviceKey } = secrets;

    const results: { date: string; game_type: string; status: string; detail?: string }[] = [];
    let generated = 0;

    for (let round = 0; round < count; round++) {
      const connDate = await findNextMissingDate(supabaseUrl, serviceKey, 'connections', daysAhead);
      const crossDate = await findNextMissingDate(supabaseUrl, serviceKey, 'crossword', daysAhead);

      if (!connDate && !crossDate) {
        log('all_filled', { daysAhead });
        break;
      }

      if (connDate) {
        try {
          const id = await restNextval(supabaseUrl, serviceKey, 'connections_puzzle_id_seq', generated + round + 1);
          log('generating', { type: 'connections', date: connDate, id });
          const puzzle = await generateConnections(anthropicApiKey, secrets, connDate, id);
          const ins = await restInsertGame(supabaseUrl, serviceKey, {
            game_type: 'connections',
            game_date: connDate,
            puzzle_data: puzzle,
            is_published: true,
          });
          results.push({ date: connDate, game_type: 'connections', status: ins === 'duplicate' ? 'skipped_duplicate' : 'created' });
          if (ins === 'inserted') generated++;
        } catch (err) {
          const msg = err instanceof Error ? err.message : String(err);
          log('failed', { type: 'connections', date: connDate, error: msg.slice(0, 500) });
          results.push({ date: connDate, game_type: 'connections', status: 'error', detail: msg.slice(0, 500) });
        }
      }

      if (crossDate) {
        try {
          const id = await restNextval(supabaseUrl, serviceKey, 'crossword_puzzle_id_seq', generated + round + 100);
          log('generating', { type: 'crossword', date: crossDate, id });
          const puzzle = await generateCrossword(anthropicApiKey, secrets, crossDate, id);
          const ins = await restInsertGame(supabaseUrl, serviceKey, {
            game_type: 'crossword',
            game_date: crossDate,
            puzzle_data: puzzle,
            is_published: true,
          });
          results.push({ date: crossDate, game_type: 'crossword', status: ins === 'duplicate' ? 'skipped_duplicate' : 'created' });
          if (ins === 'inserted') generated++;
        } catch (err) {
          const msg = err instanceof Error ? err.message : String(err);
          log('failed', { type: 'crossword', date: crossDate, error: msg.slice(0, 500) });
          results.push({ date: crossDate, game_type: 'crossword', status: 'error', detail: msg.slice(0, 500) });
        }
      }
    }

    const elapsed = Date.now() - startMs;
    const errors = results.filter(r => r.status === 'error').length;
    log('done', { generated, elapsed, errors });

    return { success: true, generated, elapsed_ms: elapsed, results, had_errors: errors > 0 };
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    log('fatal', { error: msg.slice(0, 1500) });
    return {
      success: false,
      generated: 0,
      elapsed_ms: Date.now() - startMs,
      results: [],
      had_errors: true,
      error: msg.slice(0, 2000),
    };
  }
}
